class LeakyResource implements AutoCloseable {
    void work() throws Exception {
        throw new Exception("body failed");
    }
    @Override
    public void close() throws Exception {
        throw new Exception("close failed");
    }
}

public class App {
    public static void main(String[] args) {
        try {
            try (LeakyResource r = new LeakyResource()) {
                r.work();
            }
        } catch (Exception e) {
            System.out.println("Primary: " + e.getMessage());
            for (Throwable s : e.getSuppressed()) {
                System.out.println("Suppressed: " + s.getMessage());
            }
        }
    }
}

class Resource implements AutoCloseable {
    Resource() { System.out.println("Resource opened"); }
    public void work() { 
        System.out.println("Error occurred");
        throw new RuntimeException("oops"); 
    }
    @Override public void close() { System.out.println("Resource closed"); }
}

public class App {
    public static void main(String[] args) {
        try (Resource r = new Resource()) {
            r.work();
        } catch (RuntimeException e) {
            System.out.println("Handled: " + e.getMessage());
        } finally {
            System.out.println("Finally runs");
        }
    }
}

