import java.io.*;
import java.util.*;

public class App {
    public static void main(String[] args) throws IOException {
        String csv = "Aisha,A\nRaj,B\nPriya,A";
        StringWriter output = new StringWriter();
        Map<String, Integer> counts = new HashMap<>();

        try (BufferedReader reader = new BufferedReader(new StringReader(csv));
             PrintWriter writer = new PrintWriter(output)) {

            writer.println("=== Grade Report ===");
            String line;
            while ((line = reader.readLine()) != null) {
                String[] parts = line.split(",");
                String name = parts[0], grade = parts[1];
                writer.println(name + ": " + grade);
                counts.merge(grade, 1, Integer::sum);
            }
        }  // both closed: PrintWriter first (declared 2nd), BufferedReader second

        System.out.print(output);
        System.out.println("A count: " + counts.getOrDefault("A", 0) +
                           ", B count: " + counts.getOrDefault("B", 0));
    }
}

class TransactionManager implements AutoCloseable {
    private boolean active = false;
    private boolean committed = false;
    private boolean closed = false;

    TransactionManager() {
        active = true;
        System.out.println("Transaction started");
    }

    void execute(String sql) {
        if (!active || closed)
            throw new IllegalStateException("Transaction is not active");
        System.out.println("execute: " + sql);
    }

    void commit() {
        if (!active || closed) throw new IllegalStateException("Cannot commit: not active");
        committed = true;
    }

    @Override
    public void close() {
        if (closed) return;  // idempotent
        closed = true;
        active = false;
        if (committed) System.out.println("committed and closed");
        else           System.out.println("rolled back and closed");
    }
}

public class App {
    public static void main(String[] args) {
        // Committed transaction
        try (TransactionManager tx = new TransactionManager()) {
            tx.execute("INSERT users");
            tx.execute("UPDATE accounts");
            tx.commit();
        }

        // Rolled back (exception)
        System.out.println("Rolled back (not committed):");
        try (TransactionManager tx = new TransactionManager()) {
            tx.execute("DELETE logs");
            // no commit — rolls back on close
        }
    }
}

import java.io.*;

public class App {
    public static void main(String[] args) {
        String[] files = {"hello world java", "one two", "this is a test line"};
        int total = 0;

        for (int i = 0; i < files.length; i++) {
            int wordCount = 0;
            try (BufferedReader reader = new BufferedReader(new StringReader(files[i]))) {
                String line;
                while ((line = reader.readLine()) != null) {
                    wordCount += line.split("\\s+").length;
                }
