                total += wordCount;
            } catch (IOException e) {
                System.out.println("File " + (i + 1) + ": error — " + e.getMessage());
            }
        }
        System.out.println("Total words: " + total);
    }
}

import java.util.*;

class SimConnection implements AutoCloseable {
    SimConnection() { System.out.println("Conn opened"); }
    public void close() { System.out.println("Conn closed"); }
}

class SimStatement implements AutoCloseable {
    private final String sql;
    SimStatement(SimConnection conn, String sql) {
        this.sql = sql;
        System.out.println("Stmt prepared: " + sql);
    }
    String getSql() { return sql; }
    public void close() { System.out.println("Stmt closed"); }
}

class SimResultSet implements AutoCloseable {
    private final List<String[]> rows;
    private int idx = 0;
    private boolean throwOnClose;

    SimResultSet(SimStatement stmt) throws Exception {
        System.out.println("RS opened");
        if (stmt.getSql().startsWith("BAD")) {
            throwOnClose = true;
            throw new Exception("Syntax error in: " + stmt.getSql());
        }
        rows = List.of(
            new String[]{"Aisha", "Engineering"},
            new String[]{"Raj", "Sales"}
        );
    }

    boolean next() { return idx < rows.size(); }
    String getString(int col) { return rows.get(idx)[col]; }
    void advance() { idx++; }

    public void close() {
        System.out.println(throwOnClose ? "RS closed (suppressed in real JDBC)" : "RS closed");
    }
}

public class App {
    static void runQuery(String sql) {
        try (SimConnection conn = new SimConnection();
             SimStatement stmt = new SimStatement(conn, sql)) {
            try (SimResultSet rs = new SimResultSet(stmt)) {
                while (rs.next()) {
                    System.out.println("Row: " + rs.getString(0) + " | " + rs.getString(1));
                    rs.advance();
                }
            } catch (Exception e) {
                System.out.println("Primary error: " + e.getMessage());
                for (Throwable s : e.getSuppressed())
                    System.out.println("Suppressed: " + s.getMessage());
            }
        }
    }

    public static void main(String[] args) {
        runQuery("SELECT * FROM users");
        System.out.println("---");
        runQuery("BAD SQL");
    }
}
